const raw = ($json.stdout || '').trim();
const allLines = raw.split('\n').filter(l => l && !l.startsWith('received_at'));

if (allLines.length === 0) {
  return [{
    json: {
      telegram_text: '\u{1F4CA} Утренняя сводка\n\nДанных пока нет. Открой Health Agent и нажми Send Now.',
      has_data: false,
    }
  }];
}

function parseLine(line) {
  // Last field (alerts) is quoted and may contain commas
  const alertsMatch = line.match(/,"([^"]*)"$/);
  const alertsStr = alertsMatch ? alertsMatch[1] : '';
  const core = alertsMatch ? line.slice(0, line.length - alertsMatch[0].length) : line;
  const parts = core.split(',');
  return {
    received_at: parts[0] || '',
    timestamp:   parts[1] || '',
    heart_rate:  parts[2] ? parseFloat(parts[2]) : null,
    glucose_raw: parts[3] ? parseFloat(parts[3]) : null,
    glucose_mmol:parts[4] ? parseFloat(parts[4]) : null,
    weight:      parts[5] ? parseFloat(parts[5]) : null,
    sleep_hours: parts[6] ? parseFloat(parts[6]) : null,
    alert_count: parts[7] ? parseInt(parts[7])   : 0,
    alerts: alertsStr,
  };
}

const latest = parseLine(allLines[allLines.length - 1]);
const todayUTC = new Date().toISOString().slice(0, 10);
const latestDate = latest.received_at ? latest.received_at.slice(0, 10) : '';
const isToday = latestDate === todayUTC;

const tz = $env.TZ || 'UTC';
const receivedTime = latest.received_at
  ? new Date(latest.received_at).toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit', timeZone: tz })
  : '';

const lines = ['\u{1F4CA} Утренняя сводка', ''];

if (isToday) {
  lines.push(`Последние данные сегодня в ${receivedTime}`);
} else {
  lines.push(`\u26A0\uFE0F Сегодняшних данных ещё нет. Последний замер: ${latestDate || 'неизвестно'}`);
}

lines.push('');

if (latest.heart_rate !== null)
  lines.push(`\u2764\uFE0F Пульс: ${latest.heart_rate} уд/мин${latest.heart_rate > 85 ? ' \u26A0\uFE0F' : ' \u2705'}`);
if (latest.glucose_mmol !== null)
  lines.push(`\u{1FA78} Глюкоза: ${latest.glucose_mmol.toFixed(1)} ммоль/л${latest.glucose_mmol > 6.0 ? ' \u26A0\uFE0F' : ' \u2705'}`);
if (latest.weight !== null)
  lines.push(`\u2696\uFE0F Вес: ${latest.weight} кг`);
if (latest.sleep_hours !== null)
  lines.push(`\u{1F634} Сон: ${latest.sleep_hours} ч${latest.sleep_hours < 6 ? ' \u26A0\uFE0F' : ' \u2705'}`);

if (latest.alert_count > 0 && latest.alerts) {
  lines.push('');
  lines.push(`\u{1F534} Нарушения: ${latest.alerts}`);
}

if (!isToday) {
  lines.push('');
  lines.push('Открой приложение Health Agent и нажми Send Now.');
}

return [{
  json: {
    telegram_text: lines.join('\n'),
    has_data: true,
    is_today: isToday,
  }
}];

const raw = ($json.stdout || '').trim();
const allLines = raw.split('\n').filter(l => l && !l.startsWith('received_at'));

const todayUTC = new Date().toISOString().slice(0, 10);
const todayLines = allLines.filter(l => l.startsWith(todayUTC));

const hasToday = todayLines.length > 0;
const shouldSend = !hasToday;

const telegram_text = shouldSend
  ? '\u23F0 Вечернее напоминание\n\nБраток, сегодня данные так и не пришли.\nОткрой Health Agent и нажми Send Now — займёт 5 секунд.'
  : '';

return [{
  json: {
    has_today: hasToday,
    should_send: shouldSend,
    telegram_text,
  }
}];
